parameters.jsCode:
const output = $('AI Agent - Orquestrador de Vendas').first().json.output || '';
const instance = $('Code - Checar Horário + Montar Contexto do Agente').first().json.instance;
const remoteJid = $('Code - Checar Horário + Montar Contexto do Agente').first().json.remoteJid;

// Quebra por parágrafos duplos ou linhas simples longas
const chunks = output.split(/\n\n+/).map(s => s.trim()).filter(Boolean);

if (chunks.length === 0) {
  return [{ json: { output, instance, remoteJid } }];
}

return chunks.map((chunk) => ({
  json: { output: chunk, instance, remoteJid }
}));
